quiz.question:
以下代码的输出是什么？

```go
func main() {
    fns := make([]func(), 3)
    for i := 0; i < 3; i++ {
        x := i
        fns[i] = func() { fmt.Print(x, " ") }
    }
    for _, f := range fns {
        f()
    }
}
```

